/**
 * Compaction — operations module
 *
 * AUTO-GENERATED by Phoenix VCS
 * Manages graph compaction with protected node types that are never deleted.
 */

import { createHash } from 'node:crypto';

export type StorageTier = 'hot' | 'ancestry' | 'cold';

export interface CompactionEvent {
  id: string;
  timestamp: number;
  trigger: 'size' | 'upgrade' | 'time';
  nodes_compacted: number;
}

const PROTECTED_SET = new Set([
  'node_headers',
  'provenance_edges',
  'approvals',
  'signatures',
]);

export class CompactionEngine {
  private events: CompactionEvent[] = [];

  checkTriggers(hotGraphSize: number, lastCompaction: number): boolean {
    const now = Date.now();
    const timeSinceLastCompaction = now - lastCompaction;

    // Trigger on size threshold (>1000 nodes)
    if (hotGraphSize > 1000) return true;

    // Trigger on time threshold (>24 hours since last compaction)
    if (timeSinceLastCompaction > 24 * 60 * 60 * 1000) return true;

    return false;
  }

  compact(nodes: Array<{ id: string; type: string; data: Record<string, unknown> }>): CompactionEvent {
    // Filter out protected nodes — never delete them
    const compactable = nodes.filter(n => !PROTECTED_SET.has(n.type));

    const event: CompactionEvent = {
      id: createHash('sha256').update(`compact-${Date.now()}-${compactable.length}`).digest('hex').slice(0, 16),
      timestamp: Date.now(),
      trigger: compactable.length > 500 ? 'size' : 'time',
      nodes_compacted: compactable.length,
    };

    this.events.push(event);
    return event;
  }

  getEvents(): CompactionEvent[] {
    return [...this.events];
  }

  getProtectedTypes(): string[] {
    return Array.from(PROTECTED_SET);
  }
}

export function createCompactionEngine(): CompactionEngine {
  return new CompactionEngine();
}

